import type { CreateCheckoutParams, CreateCheckoutResult, PaymentMethod } from './types';

interface PagBankCustomer {
  name: string;
  email: string;
  tax_id: string;
  phones: Array<{
    country: string;
    area: string;
    number: string;
    type: 'MOBILE';
  }>;
}

interface PagBankItem {
  name: string;
  quantity: number;
  unit_amount: number;
}

interface PagBankQrCode {
  amount: {
    value: number;
  };
  expiration_date: string;
}

interface PagBankAddress {
  street: string;
  number: string;
  complement?: string;
  locality: string;
  city: string;
  region_code: string;
  country: string;
  postal_code: string;
}

interface PagBankShipping {
  address: PagBankAddress;
}

interface PagBankOrderRequest {
  reference_id: string;
  customer: PagBankCustomer;
  items: PagBankItem[];
  qr_codes: PagBankQrCode[];
  shipping?: PagBankShipping;
  notification_urls?: string[];
}

interface PagBankOrderResponse {
  id: string;
  reference_id: string;
  status: string;
  qr_codes: Array<{
    id: string;
    text_code: string;
    base64_image: string;
  }>;
  // ... outros campos que podem vir da API do PagBank
}

export async function createPagBankPixOrder(
  orderRequest: PagBankOrderRequest,
): Promise<PagBankOrderResponse> {
  const PAGBANK_API_URL = 'https://sandbox.api.pagseguro.com/orders'; // Usando sandbox
  const PAGBANK_AUTH_TOKEN = process.env.PAGBANK_AUTH_TOKEN; // Precisamos definir isso no .env

  if (!PAGBANK_AUTH_TOKEN) {
    throw new Error('PAGBANK_AUTH_TOKEN não está definido no ambiente.');
  }

  const response = await fetch(PAGBANK_API_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${PAGBANK_AUTH_TOKEN}`,
    },
    body: JSON.stringify(orderRequest),
  });

  if (!response.ok) {
    const errorData = await response.json();
    console.error('Erro ao criar pedido PagBank:', errorData);
    throw new Error(`Erro na API do PagBank: ${response.status} - ${JSON.stringify(errorData)}`);
  }

  return response.json();
}
